var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"카운터의 힘이 강해지는 약이라고요?","JPN":"カウンターの力が強くなる薬ですって？","ENG":"A drug that enhances the powers of a Counter?","TWN":"可以增強制裁者力量的藥？"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"네… 한동안 그 소문의 엘릭서라는 물건을 찾아다녔거든요.","JPN":"はい……しばらくその噂のエリクサーという物を探し回ってたんです。","ENG":"Yes... We've been going around searching for this rumored Elixir for a while now.","TWN":"對…我們找到傳聞中的聖水。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"그러다 간신히 판매처를 찾았다 싶었는데… 그 녀석들 애초에 가짜 물건을 팔면서 우리 돈만 뜯어낼 작정이었던 거예요.","JPN":"それで、やっと販売元を見つけたと思ったんですけど……あいつらはそもそも偽物を売りつけて、俺らの金だけを巻き上げるつもりだったんですよ。","ENG":"And just when we thought we found a dealer... they were selling fake drugs and stealing our money.","TWN":"對，好不容易找到哪裡有在賣…結果他們賣的是假貨，根本是想黑吃黑，騙我們的錢。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"아무리 절박한 심정이라지만 그런 정체도 모르는 약을 함부로 쓰면 안 돼.","JPN":"いくら追い詰められたとしても、そんな得体の知れない薬をむやみに飲んじゃダメだよ。","ENG":"No matter how desperate you may feel, you should never abuse drugs of unknown origin.","TWN":"我明白你們想要變強的心情，但怎麼可以使用那種來路不明的藥呢？"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"게다가 너희들끼리 말도 없이 암매상 소굴에 들어가는 건 더 위험하다구.","JPN":"それに、あなたたちだけで黙って闇商人のアジトに入るのはもっと危ないし。","ENG":"Furthermore, going into a black marketeer's lair without telling anyone is an even greater risk.","TWN":"然後還更危險地自己跑到黑市商人的地盤。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"알고 있어.","JPN":"わかってる。","ENG":"I know.","TWN":"你說的我都知道。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"그렇지만… 우리한테는 이런 방법밖에 없는 걸 어떡해.","JPN":"でも……俺らにはこんな方法しかなかったんだ。","ENG":"But... there was no other way for us.","TWN":"可是…這是我們唯一的辦法。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"뭐어?","JPN":"はあ？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그렇지 않아! 너희도 열심히 노력하면 지금보다 훨씬 강해질 수 있다구!","JPN":"そんなことない！　あなたたちも一生懸命頑張れば、今よりもっと強くなれるって！","ENG":"That's not true! If you put in the effort, I'm certain you'll get stronger!","TWN":"才不是呢！只要努力，你們一定會變得比現在更強的！"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"미카, 넌 노력으로 카운터 등급이 바뀌었다는 얘길 들은 적 있어?","JPN":"ミカ、お前は努力だけでカウンターのランクが変わるって話、聞いたことある？","ENG":"Mika, have you heard of someone's Counter grade going up from working hard?","TWN":"米卡，你有聽說誰是靠著努力改變制裁者等級的嗎？"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그, 그건… 없는 것 같지만…","JPN":"そ、それは……ないと思うけど……","ENG":"W-well... I don't think so...","TWN":"這個嘛…好像沒聽說過…"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"사실 알고 있잖아. 우리 같은 D급은 아무리 열심히 배우려고 해도 D급이야.","JPN":"実はわかってるんだろ？　俺らみたいなDランクは、いくら頑張って勉強してもDランクだ。","ENG":"You already know. Grade Ds like us will always be Grade D, no matter how hard we try.","TWN":"你也很清楚吧，像我們這種D級制裁者，再怎麼努力也是D。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"하지만 진짜 엘릭서는 카운터가 아닌 사람도 카운터로 만들어준다고! 동영상으로 봤어!","JPN":"でも、本物のエリクサーはカウンターじゃない人でもカウンターにしてくれるんだ！　動画で見たんだから！","ENG":"But this Elixir can turn even a non-Counter into a Counter! I saw it in the video!","TWN":"但真正的聖水可以將原本不是制裁者的人變成制裁者欸！這是我在影片中看到的！"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"그걸 구할 수만 있다면 우리도…!","JPN":"それを手に入れれば、俺らも……！","ENG":"If only I could get my hands on that...!","TWN":"只要能夠得到聖水，我們也可以…！"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"흥, 기껏 구해줬더니 아직도 그런 멍청한 소릴 하는 거야?","JPN":"ふん、せっかく助けてあげたのに、まだそんなふざけたこと言ってるの？","ENG":"Hmph! Is that all you have to say after we saved your butts?","TWN":"哼，我們這麼辛苦把你們救回來，結果你們還在說這些不切實際的話？"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"이런 정신 못 차리는 바보들은 그냥 정학처분을 해버리자고!","JPN":"こんな反省の余地のないバカは、停学処分にしちゃおうよ！","ENG":"We should just give these morons a suspension!","TWN":"像這種腦袋不清楚的傢伙，直接罰他們退學啦！"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"대외적으로 아카데미의 인식에 부정적인 영향을 끼친 학생이라면 내쫓을 명분도 있잖아? 안 그래?","JPN":"対外的にアカデミーのイメージにネガティブな影響を及ぼした生徒なら、追い出す名分もあるでしょ？　違うの？","ENG":"Isn't there a rule that says students who harm the Academy's reputation can be expelled?","TWN":"對外就說他們的行為有損學院的形象，因此他們退學處分，這樣可以吧？"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"그런…!","JPN":"そんな……！","ENG":"That's...!","TWN":"什麼…！"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};